-- Сброс последовательностей (чтобы следующие ID продолжали правильно)
SELECT setval('"Categories_Id_seq"', (SELECT MAX("Id") FROM "Categories"));
SELECT setval('"Products_Id_seq"', (SELECT MAX("Id") FROM "Products"));
SELECT setval('"Orders_Id_seq"', (SELECT COALESCE(MAX("Id"), 1) FROM "Orders"));
SELECT setval('"OrderItems_Id_seq"', (SELECT COALESCE(MAX("Id"), 1) FROM "OrderItems"));